data.content:
Here's how to structure the tests using modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ErrorStatus_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        // Arrange — handler that delays so cancellation can fire
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // cooperative timeout — kills the test if it hangs
    public async Task FetchAsync_SlowServer_TimesOutViaCancellationToken()
    {
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromMinutes(5), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // TestContext.CancellationToken fires when [Timeout] expires,
        // so this will throw rather than hang for 5 minutes.
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // Minimal fake handler — avoids heavy mocking frameworks
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<CancellationToken, Task<HttpResponseMessage>> _factory;

        public FakeHandler(HttpResponseMessage response)
            : this(_ => Task.FromResult(response)) { }

        public FakeHandler(Func<CancellationToken, Task<HttpResponseMessage>> factory)
            => _factory = factory;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _factory(cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout] + _testContext.CancellationToken` | Cooperative timeout — the token fires when the timeout expires, so your async code actually stops instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]` — lets you assert the exact exception type |
| `FakeHandler` instead of mocking `HttpClient` | `HttpClient` can't be mocked directly; a custom `HttpMessageHandler` is the standard approach |
| `sealed` test class + `sealed` handler | Performance and design clarity |

The critical insight: **`[Timeout]` alone won't cancel your code** — you must pass `TestContext.CancellationToken` into the async call. Without it, the test runner can only abort the thread, which is unreliable for async work.
